"""Second patch: appends extra content to 18 articles still under 2500 words."""
import json, re

def word_count(html):
    stripped = re.sub(r'<[^>]+>', ' ', html)
    stripped = re.sub(r'\s+', ' ', stripped).strip()
    return len(stripped.split()) if stripped else 0

